        public void GridLoad()
        {
            try
            {
                if (Convert.ToInt64(combocompcode.SelectedValue) > 0)
                {
                    lbltotal2.Text = "";
                    listView2.Items.Clear(); listfilter.Items.Clear();
                    txtsearch1.Text = ""; Cursor = Cursors.WaitCursor;
                    string sel1 = "select B.GTNORDERENTRYID, A.COMPCODE,B.ORDERNO, B.ORDERQTY  from gtcompmast a join GTNORDERENTRY b on A.GTCOMPMASTID=B.COMPCODE  where  a.compcode='" + combocompcode.Text + "' order by 3";
                    DataSet ds = Utility.ExecuteSelectQuery(sel1, "GTNORDERENTRY");
                    DataTable dt = ds.Tables["GTNORDERENTRY"];
                    if (dt.Rows.Count > 0)
                    {
                        int j = 1;

                        foreach (DataRow myRow in dt.Rows)
                        {
                            ListViewItem list1 = new ListViewItem();
                            list1.SubItems.Add(j.ToString());
                            list1.SubItems.Add(myRow["GTNORDERENTRYID"].ToString());
                            list1.SubItems.Add(myRow["ORDERNO"].ToString());
                            list1.SubItems.Add(myRow["ORDERQTY"].ToString());
                            this.listfilter.Items.Add((ListViewItem)list1.Clone());
                            if (j % 2 == 0)
                            {
                                list1.BackColor = Color.WhiteSmoke;
                            }
                            else
                            {
                                list1.BackColor = Color.White;
                            }
                            listView2.Items.Add(list1);
                            j++;
                        }
                        lbltotal2.Text = "" + combocompcode.Text + " Total Record's : " + listView2.Items.Count;

                        crystalReportViewer1.ReportSource = null; crystalReportViewer1.Refresh();
                    }

                    Cursor = Cursors.Default;
                }
            }
            catch (Exception ex)
            {
                // MessageBox.Show("Error: " + ex.Message, " Error ", MessageBoxButtons.OK, MessageBoxIcon.Information);
            }
        }

   

