N R.GTPRODELID=Q.ISSNO JOIN GTATTVALMAST ZA ON ZA.GTATTVALMASTID = B.GSM JOIN GTATTVALMAST ZB ON ZB.GTATTVALMASTID = B.GG JOIN GTATTVALMAST ZC ON ZC.GTATTVALMASTID = B.LL WHERE B.ORDERNO = '" + e.Item.SubItems[3].Text + "' AND Q.MP = 'Yes' ) A ) A WHERE A.PROCESSGROUP = 'DYED FABRIC' AND A.ORDERNO = '" + e.Item.SubItems[3].Text + "' UNION ALL SELECT 1 SNO,4 SNO1,A.PROCESSNAME||' '||A.TRANSTYPE TRANS,A.GRNNO DOCID,A.GRNDATE DOCDATE,A.SUPPLIER,A.ARTICLEID||' / '||A.COLORNAME||' / '|| A.DESIGN||' / '||A.GSM||' / '||A.GG||' / '||A.LL||' / '||A.KDIA||' / '||A.FDIA ARTDESC, A.GRNBAGS BAGS,A.GRNQTY POQTY,A.UNITNAME,0 LOSS,0 PER,A.PRE,A.RETQTY FROM ( SELECT A.GTPOID, A.GTPODETID, A.COMPCODE, A.COMPNAME, A.DOCID PONO, A.DOCDATE PODATE, A.PAYTERM, A.SUPPLIER, A.YARNID, A.FABRICID, A.ARTICLEID, A.COLORNAME, A.UNITNAME, A.BUYERCODE, A.PROCESSNAME, A.ORDERNO, A.POTYPE, A.TRANSTYPE, A.BALQTY, A.REQNO, A.POQTY, A.PRICE, A.GRNQTY, A.EXCESSQTY, A.RETQTY, A.BILLQTY, A.BILLBALQTY, A.DETAILID, A.LOTNO, A.SHADEREFNO, A.TAX, A.GRNNO, A.GRNDATE,  A.GRNDETAILID, A.RETBALQTY, A.NETAMOUNT, A.DESIGN, A.KDIA, A.FDIA,A.SUPPDCNO,A.GRNBAGS,A.PRE,A.GSM,A.GG,A.LL FROM (SELECT A.GTPOID, B.GTPODETID, C.COMPCODE, C.COMPNAME, A.DOCID,     A.DOCDATE, D.PAYTERM, A.DUEDATE, E.FINYR,     F.ADSCHEME TAXTEMP, A.SUPPLIER, B.YARNID, B.FABRICID, G.SHORTCODE ARTICLEID, J.COLORNAME, L.UNITNAME, M.BUYERCODE, K.PROCESSNAME, BB.ORDERNO, BB.POTYPE, BB.TRANSTYPE, BB.BALQTY, H.REQNO, BB.POQTY, BB.POPRICE PRICE, BB.TOTALGRNQTY GRNQTY, BB.EXCESSQTY, BB.RETQTY, BB.BILLQTY, (BB.TOTALGRNQTY - (BB.RETQTY + BB.BILLQTY)) RETBALQTY, (BB.TOTALGRNQTY - (BB.RETQTY + BB.BILLQTY)) BILLBALQTY, B.DETAILID, BB.LOTNO, BB.SHADEREFNO, B.TAX, AA.DOCID GRNNO, AA.DOCDATE GRNDATE, BB.GTPOINWARDDETID GRNDETAILID, A.NETAMOUNT, Z.DESIGN, X.DIA KDIA, Y.DIA FDIA,AA.SUPPDCNO,BB.GRNBAGS,AA.PRE,ZA.ATTVALUE GSM,ZB.ATTVALUE GG,ZC.ATTVALUE LL FROM GTPO A JOIN GTPODET B ON A.GTPOID = B.GTPOID  JOIN GTCOMPMAST C ON C.GTCOMPMASTID = A.COMPCODE LEFT OUTER J